def count_up_to(n):
    if n <= 2:
        return []
    sieve = [True] * n
    for p in range(2, int(n**0.5) + 1):
        if sieve[p]:
            for i in range(p * p, n, p):
                sieve[i] = False
    return [p for p in range(2, n) if sieve[p]]
